#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_create_eas_database {
  void create_eas_database() {
    // 1. Connect to the SQLite database "test_db.sqlite"
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // 2. Create the necessary directories for the file path
    std::filesystem::create_directories("data");

    // 3. Execute the ATTACH DATABASE statement
    conn.execute("ATTACH DATABASE 'data/eas_database.db' AS EAS_DB;").value();
  }
}
```

