namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // 1. Establish database connection
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false; // Connection failed
    }
    auto conn = *conn_result;

    // 2. Construct UPDATE statement with SET clauses
    auto update_stmt = update<Document>(
        "is_deleted"_c.set(1),
        "deleted_at"_c.set("CURRENT_TIMESTAMP")
    );

    // 3. Add WHERE condition using IN clause
    auto where_condition = where("doc_id"_c.in(ids));

    // 4. Combine UPDATE with WHERE condition
    auto final_stmt = update_stmt | where_condition;

    // 5. Execute the update
    auto result = conn.execute(conn.to_sql(final_stmt));

    // 6. Return success status
    return result;
}

}  // namespace soft_delete_records
```

