namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Start transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  try {
    // Define column literals
    auto balance_c = "balance"_c;
    auto account_id_c = "account_id"_c;

    // Check if from_account has sufficient funds
    auto from_account_result = (sqlgen::read<Account> | sqlgen::where(account_id_c == from_account_id))(conn);
    if (!from_account_result) {
      conn->rollback();
      return false;
    }

    auto from_account = from_account_result.value();
    if (from_account.balance < amount) {
      conn->rollback();
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from = sqlgen::update<Account>(balance_c.set(balance_c - amount)) 
                       | sqlgen::where(account_id_c == from_account_id);
    auto update_result = conn->execute(conn->to_sql(update_from));
    if (!update_result) {
      conn->rollback();
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to = sqlgen::update<Account>(balance_c.set(balance_c + amount)) 
                     | sqlgen::where(account_id_c == to_account_id);
    auto update_to_result = conn->execute(conn->to_sql(update_to));
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
